        [hs_object_source_detail_1] = CASE WHEN @hs_object_source_detail_1_Clear = 1 THEN NULL ELSE ISNULL(@hs_object_source_detail_1, [hs_object_source_detail_1]) END,
        [hs_sender_company_domain] = CASE WHEN @hs_sender_company_domain_Clear = 1 THEN NULL ELSE ISNULL(@hs_sender_company_domain, [hs_sender_company_domain]) END,
        [hs_invoice_latest_company_name] = CASE WHEN @hs_invoice_latest_company_name_Clear = 1 THEN NULL ELSE ISNULL(@hs_invoice_latest_company_name, [hs_invoice_latest_company_name]) END,
        [hs_invoice_link] = CASE WHEN @hs_invoice_link_Clear = 1 THEN NULL ELSE ISNULL(@hs_invoice_link, [hs_invoice_link]) END,
        [hs_object_source_detail_3] = CASE WHEN @hs_object_source_detail_3_Clear = 1 THEN NULL ELSE ISNULL(@hs_object_source_detail_3, [hs_object_source_detail_3]) END,
        [hs_invoice_date] = CASE WHEN @hs_invoice_date_Clear = 1 THEN NULL ELSE ISNULL(@hs_invoice_date, [hs_invoice_date]) END,
        [hs_sender_company_country] = CASE WHEN @hs_sender_company_country_Clear = 1 THEN NULL ELSE ISNULL(@hs_sender_company_country, [hs_sender_company_country]) END,
        [hs_invoice_source] = CASE WHEN @hs_invoice_source_Clear = 1 THEN NULL ELSE ISNULL(@hs_invoice_source, [hs_invoice_source]) END,
        [hs_store_payment_method_at_checkout] = CASE WHEN @hs_store_payment_method_at_checkout_Clear = 1 THEN NULL ELSE ISNULL(@hs_store_payment_method_at_checkout, [hs_store_payment_method_at_checkout]) END,
        [hs_recipient_company_address2] = CASE WHEN @hs_recipient_company_address2_Clear = 1 THEN NULL ELSE ISNULL(@hs_recipient_company_address2, [hs_recipient_company_address2]) END,
        [hs_title] = CASE WHEN @hs_title_Clear = 1 THEN NULL ELSE ISNULL(@hs_title, [hs_title]) END,
        [__mj_integration_SyncStatus] = ISNULL(@__mj_integration_SyncStatus, [__mj_integration_SyncStatus]),
        [__mj_integration_LastSyncedAt] = CASE WHEN @__mj_integration_LastSyncedAt_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_LastSyncedAt, [__mj_integration_LastSyncedAt]) END,
        [__mj_integration_LastSyncedSnapshot] = CASE WHEN @__mj_integration_LastSyncedSnapshot_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_LastSyncedSnapshot, [__mj_integration_LastSyncedSnapshot]) END,
        [__mj_integration_SyncMessage] = CASE WHEN @__mj_integration_SyncMessage_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_SyncMessage, [__mj_integration_SyncMessage]) END
    WHERE
        [hs_object_id] = @hs_object_id

    -- Check if the update was successful
    IF @@ROWCOUNT = 0
        -- Nothing was updated, return no rows, but column structure from base view intact, semantically correct this way.
        SELECT TOP 0 * FROM [hubspot].[vwInvoices] WHERE 1=0
    ELSE
        -- Return the updated record so the caller can see the updated values and any calculated fields
        SELECT
                                        *
                                    FROM
                                        [hubspot].[vwInvoices]
                                    WHERE
                                        [hs_object_id] = @hs_object_id
                                    
END
GO

GRANT EXECUTE ON [hubspot].[spUpdateinvoices] TO [cdp_Developer], [cdp_Integration]
GO

------------------------------------------------------------
----- TRIGGER FOR __mj_UpdatedAt field for the invoices table
------------------------------------------------------------
IF OBJECT_ID('[hubspot].[trgUpdateinvoices]', 'TR') IS NOT NULL
    DROP TRIGGER [hubspot].[trgUpdateinvoices];
GO
CREATE TRIGGER [hubspot].trgUpdateinvoices
ON [hubspot].[invoices]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE
        [hubspot].[invoices]
    SET
        __mj_UpdatedAt = GETUTCDATE()
    FROM
        [hubspot].[invoices] AS _organicTable
    INNER JOIN
        INSERTED AS I ON
        _organicTable.[hs_object_id] = I.[hs_object_id];
END;
GO
        